import { Component, OnInit, OnDestroy } from '@angular/core';
import { Subscription } from 'rxjs';
import { ActivitywisereportService } from './activitywisereport.service';
import { UnitmasterService } from '../../setup/unitmaster/unitmaster.service';
import { MatSnackBar } from '@angular/material/snack-bar';

@Component({
  selector: 'ux-activitywisereport',
  templateUrl: './activitywisereport.component.html',
  styleUrls: ['./activitywisereport.component.scss']
})
export class ActivitywisereportComponent implements OnInit, OnDestroy {
  from_date = '';
  to_date = '';
  unit_id = '';
  report_data: any[] = [];
  grand_total = 0;
  grand_orders = 0;
  searched = false;

  units_list: any[] = [];
  private unit_subscription: Subscription;

  constructor(
    private activitywisereportService: ActivitywisereportService,
    private unitService: UnitmasterService,
    private _snackBar: MatSnackBar
  ) {}

  ngOnInit() {
    this.unitService.getAllUnitmaster().subscribe();
    this.unit_subscription = this.unitService.unitmasterChanged.subscribe((units: any[]) => {
      this.units_list = units;
    });
  }

  async onSearchClick() {
    if (this.from_date && this.to_date) {
      this.report_data = [];
      this.grand_total = 0;
      this.grand_orders = 0;
      this.searched = true;
      try {
        const res: any = await this.activitywisereportService.getActivityWiseReport({
          from_date: this.from_date,
          to_date: this.to_date,
          unit_id: this.unit_id || undefined
        });
        if (res.messagecode === 100) {
          this.report_data = res.grouped_by_activity;
          this.report_data.forEach(row => {
            this.grand_total += Number(row.total || 0);
            this.grand_orders += Number(row.orders?.length || 0);
          });
        }
      } catch (err) {
        this._snackBar.open('Failed to fetch report', 'Error', { duration: 3000 });
      }
    } else {
      this._snackBar.open('Select From Date and To Date', 'Information', { duration: 3000 });
    }
  }

  ngOnDestroy() {
    this.unit_subscription?.unsubscribe();
  }
}
